import 'dart:async';
//import 'package:dio/dio.dart';
import 'package:flutter/foundation.dart';
import 'package:path_provider/path_provider.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:yaml/yaml.dart';


enum CacheType {
  // no cache is loaded by default
  NONE,

  // cache is loaded only when first run on startup with no internet connection and user token and profile are not available locally
  CACHE_ONCE_AND_LOAD_AFTER_LOGIN,

  // cache is loaded after every successful internet call. User profile data is also cached and saved to cache.json for each user token
  CACHE_PERMANENTLY
}


class CacheManager {
  final String APP_SETTINGS = 'app-settings'; 
  // cache data
  // shared preference used for user authentication and tokens
  static const _prefs = await SharedPreferences.getInstance();

  // path to the cache directory, where the data is saved in JSON format after every successful network call
  static final cachePath = '${(await getApplicationDocumentsDirectory().path).replaceAll(" ", "\\ ")}/$APP_SETTINGS/cache';

  // the type of the CacheManager
  CacheType cacheType; 

  // singleton instance for this class. 
  // private to avoid multiple instances for the same class 
  static CacheManager _instance;

  static CacheManager getInstance(this cacheType = CacheType.CACHE_ONCE_AND_LOAD_AFTER_LOGIN) {
    if (_instance == null){
      _instance = new CacheManager();
      _instance.cacheType = cacheType;
    }
    
    return _instance;
  }

}
